// Send message to Telegram with optional inline keyboard
// Uses this.helpers.httpRequest so reply_markup stays a proper
// nested object — not a stringified string inside JSON.
const d = $('🧠 Master Handler').item.json;
const BOT_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';

if (!d.chatId || !d.text) {
  return [{ json: { skipped: true } }];
}

const body = {
  chat_id: String(d.chatId),
  text: d.text
};

// Only add reply_markup if there is actually a keyboard
if (d.keyboard && d.keyboard.inline_keyboard && d.keyboard.inline_keyboard.length > 0) {
  body.reply_markup = d.keyboard;
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage',
  body,
  json: true
});

return [{ json: { ok: true, messageId: response.result?.message_id } }];

const BOT_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';
const d = $json;

console.log('Notifying chatId:', d.chatId);
console.log('resultCount:', d.resultCount);

// First send a plain text message with no special characters
const text = 'Great news! I found ' + d.resultCount + ' jobs for you on LinkedIn.\n\nHow would you like your results?';

// Send the message
let response;
try {
  response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage',
    body: {
      chat_id: String(d.chatId),
      text: text,
      reply_markup: {
        inline_keyboard: [
          [{ text: 'Excel Spreadsheet (.xlsx)', callback_data: 'DEL~excel' }],
          [{ text: 'Text Summary in Chat',      callback_data: 'DEL~text'  }],
          [{ text: 'Both (Preview + Excel)',    callback_data: 'DEL~both'  }]
        ]
      }
    },
    json: true
  });
} catch(e) {
  console.log('First attempt failed:', e.message);

  // Fallback — send with no keyboard at all
  response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage',
    body: {
      chat_id: String(d.chatId),
      text: 'Your results are ready. Found ' + d.resultCount + ' jobs. Reply with excel, text, or both to get your results.'
    },
    json: true
  });
}

console.log('Telegram response:', JSON.stringify(response));

return [{ json: { sent: true, chatId: d.chatId, resultCount: d.resultCount } }];

const p = $json.apifyPayload;

const apifyInput = {
  keyword: [p.jobRole],
  location: p.location,
  publishedAt: 'r2592000',
  enrichCompanyData: false,
  saveOnlyUniqueItems: true
};

const webhookCfg = [{
  eventTypes: ['ACTOR.RUN.SUCCEEDED', 'ACTOR.RUN.FAILED'],
  requestUrl: 'https://YOUR_N8N_SUBDOMAIN.app.n8n.cloud/webhook/jobfindr-apify-done?chatId=' + p.chatId
}];

const encoded = Buffer.from(JSON.stringify(webhookCfg)).toString('base64');

return [{ json: {
  ...$json,
  apifyInput,
  apifyUrl: 'https://api.apify.com/v2/acts/cheap_scraper~linkedin-job-scraper/runs?token=YOUR_APIFY_API_TOKEN&webhooks=' + encoded
} }];

const masterData = $('🧠 Master Handler').item.json;
const results = masterData.results || [];

if (results.length === 0) {
  return [{ json: { error: 'No results', chatId: masterData.chatId } }];
}

const rows = results.map((job, i) => ({
  '#':               i + 1,
  'Job Title':       job.title           || 'N/A',
  'Company':         job.company         || 'N/A',
  'Location':        job.location        || 'N/A',
  'Contract Type':   job.employmentType  || 'N/A',
  'Work Type':       job.workType        || 'N/A',
  'Experience':      job.experienceLevel || 'N/A',
  'Salary':          job.salary          || 'Not listed',
  'Applicants':      job.applicants      || 'N/A',
  'Posted':          job.postedAt        || 'N/A',
  'Apply Link':      job.jobUrl          || 'N/A',
  'Recruiter':       job.recruiterName   || 'N/A',
  'Recruiter URL':   job.recruiterUrl    || 'N/A',
  'Job ID':          job.jobId           || 'N/A',
  'Scraped On':      new Date().toISOString().split('T')[0]
}));

return rows.map(r => ({ json: r }));

const staticData = $getWorkflowStaticData('global');
const body  = $json.body || $json;
const query = $json.query || {};

console.log('Full body:', JSON.stringify(body));
console.log('Query params:', JSON.stringify(query));

const runId  = body.eventData?.actorRunId
            || body.resource?.id
            || body.data?.id;

const status = body.eventType || body.status || '';

// chatId comes from URL query param — much more reliable than staticData
const chatId = query.chatId
            || body.chatId
            || staticData.runToChat?.[runId];

console.log('runId:', runId);
console.log('chatId:', chatId);
console.log('status:', status);

if (!chatId) {
  return [{ json: { error: 'No chatId found', runId, query, body } }];
}

const failed = status.includes('FAILED');
return [{ json: {
  chatId,
  runId,
  failed,
  errorText: failed ? 'Sorry, the scrape failed. Please try /search again.' : null
} }];

const BOT_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage',
  body: {
    chat_id: String($json.chatId),
    text: $json.errorText
  },
  json: true
});

return [{ json: { sent: true } }];

const staticData = $getWorkflowStaticData('global');
const allItems   = $input.all();

// Get runId from the webhook — it was stored in Handle Apify Callback
// We stored chatId against runId in pendingDelivery inside Fetch node
// Find the first item that has a runId, or get it from pendingDelivery keys
const pendingDelivery = staticData.pendingDelivery || {};
const pendingKeys     = Object.keys(pendingDelivery);
const runId           = pendingKeys[pendingKeys.length - 1];
const chatId          = pendingDelivery[runId];

console.log('runId:', runId);
console.log('chatId:', chatId);
console.log('Total items:', allItems.length);

if (!chatId) {
  return [{ json: { error: 'No chatId', pendingDelivery, itemCount: allItems.length } }];
}

// Clean up pendingDelivery entry
delete staticData.pendingDelivery[runId];

const seen    = new Set();
const results = allItems
  .map(i => i.json)
  .filter(job => job && job.jobTitle)
  .map(job => ({
    title:           job.jobTitle,
    company:         job.companyName,
    location:        job.location,
    salary:          job.salaryInfo        || null,
    jobUrl:          job.jobUrl            || job.applyUrl,
    postedAt:        job.publishedAt       || job.postedTime,
    employmentType:  job.contractType,
    experienceLevel: job.experienceLevel,
    workType:        job.workType,
    applicants:      job.applicationsCount || null,
    description:     job.jobDescription
      ? job.jobDescription.substring(0, 300)
      : null,
    recruiterName:   job.posterFullName    || null,
    recruiterUrl:    job.posterProfileUrl  || null,
    jobId:           job.jobId
  }))
  .filter(job => {
    if (!job.jobUrl || seen.has(job.jobUrl)) return false;
    seen.add(job.jobUrl);
    return true;
  });

if (!staticData.results) staticData.results = {};
staticData.results[chatId] = results;
if (staticData.scrapeJobs) delete staticData.scrapeJobs[chatId];

console.log('Stored', results.length, 'results for chatId:', chatId);

return [{ json: { chatId, runId, resultCount: results.length } }];

const staticData = $getWorkflowStaticData('global');
const chatId = $json.chatId;
const runId  = $json.runId;
const APIFY_TOKEN = 'YOUR_APIFY_API_TOKEN';

console.log('Fetching results for chatId:', chatId, 'runId:', runId);

// Store chatId so Process & Store Results can find it
if (!staticData.pendingDelivery) staticData.pendingDelivery = {};
staticData.pendingDelivery[runId] = chatId;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.apify.com/v2/actor-runs/' + runId + '/dataset/items?token=' + APIFY_TOKEN + '&limit=100&clean=true',
  json: true
});

const items = Array.isArray(response) ? response : [];

console.log('Total items fetched:', items.length);

if (items.length === 0) {
  return [{ json: { chatId, runId, noResults: true } }];
}

return items.map(item => ({ json: item }));

// ============================================================
// JOBFINDR — STATELESS MASTER HANDLER
// ============================================================
// HOW THIS WORKS:
// Instead of storing conversation state in n8n (which causes
// race conditions and repeated messages), ALL accumulated
// answers are encoded inside each button's callback_data.
// When a user taps a button, we decode their full history
// from the button data itself. No shared state, no races.
//
// callback_data format: STEP~jobIdx~typeCode~locIdx~expIdx~salIdx
// Example: S~0~F~3~1~2 means:
//   Step=Salary, job=0(SoftwareEng), type=F(FullTime),
//   loc=3(Nigeria), exp=1(MidLevel), sal=2(60-100K)
//
// Special indices: 99 = user typed custom text (stored briefly
// in staticData only for that single exchange)
// ============================================================

const staticData = $getWorkflowStaticData('global');
// staticData is ONLY used for:
// 1. awaitingCustom[chatId] — flag: waiting for typed text
// 2. customJob[chatId]      — stores custom job text briefly
// 3. customLoc[chatId]      — stores custom location briefly
// 4. scrapeJobs[chatId]     — tracks active Apify runs
// 5. results[chatId]        — stores scrape results for delivery
if (!staticData.awaitingCustom) staticData.awaitingCustom = {};
if (!staticData.customJob) staticData.customJob = {};
if (!staticData.customLoc) staticData.customLoc = {};
if (!staticData.scrapeJobs) staticData.scrapeJobs = {};
if (!staticData.results) staticData.results = {};

// ── Parse incoming update ────────────────────────────────────
const raw = $json.body || $json;
const isCallback = !!(raw.callback_query);
const msg = raw.message || {};
const cbq = raw.callback_query || {};

const chatId = String(
  isCallback ? (cbq.message?.chat?.id || cbq.from?.id) : (msg.chat?.id || '')
);
const messageText = isCallback ? (cbq.data || '') : (msg.text || '').trim();
const callbackQueryId = isCallback ? cbq.id : null;
const username = isCallback
  ? (cbq.from?.first_name || 'there')
  : (msg.from?.first_name || 'there');

if (!chatId) {
  return [{ json: { skip: true } }];
}

// ── Lookup tables ────────────────────────────────────────────
const JOB_ROLES = [
  'Software Engineer',   // 0
  'Data Analyst',        // 1
  'UX/UI Designer',      // 2
  'Product Manager',     // 3
  'DevOps Engineer',     // 4
  'Business Analyst',    // 5
  'AI/ML Engineer',      // 6
  'Mobile Developer',    // 7
  'Cybersecurity Analyst', // 8
  'Marketing Manager'    // 9
];
const JOB_EMOJIS = ['💻','📊','🎨','📈','🔧','💼','🤖','📱','🔒','📣'];
const JOB_TYPES  = { F:'Full-Time', P:'Part-Time', C:'Contract', I:'Internship', A:'Any' };
const LOCATIONS  = ['Remote','United Kingdom','United States','Nigeria','Germany','Canada'];
const LOC_FLAGS  = ['🌍','🇬🇧','🇺🇸','🇳🇬','🇩🇪','🇨🇦'];
const EXP_LEVELS = ['Entry Level','Mid-Senior Level','Senior Level','Director / Executive','Internship','Any'];
const SALARIES   = ['Under $30K / £25K','$30K-60K / £25K-50K','$60K-100K / £50K-80K','$100K+ / £80K+','No Preference'];

// ── Resolvers: index → human-readable text ───────────────────
const resolveJob = (j) => j === '99'
  ? (staticData.customJob[chatId] || 'Custom Role')
  : (JOB_ROLES[parseInt(j)] || j);

const resolveType = (t) => JOB_TYPES[t] || 'Any';

const resolveLoc = (l) => l === '99'
  ? (staticData.customLoc[chatId] || 'Custom Location')
  : (LOCATIONS[parseInt(l)] || l);

const resolveExp = (e) => EXP_LEVELS[parseInt(e)] || 'Any';
const resolveSal = (s) => SALARIES[parseInt(s)] || 'No Preference';

// ── Keyboard builders ────────────────────────────────────────
// Each button encodes the FULL state needed to reach the next step.
// This means a button tap carries its own context — no stored state needed.

const jobKeyboard = () => ({
  inline_keyboard: [
    ...JOB_ROLES.map((r, i) => [{ text: JOB_EMOJIS[i] + ' ' + r, callback_data: 'J~' + i }]),
    [{ text: '✍️ Other — Type it!', callback_data: 'J~X' }]
  ]
});

// After picking job j, show type options — each carries j forward
const typeKeyboard = (j) => ({
  inline_keyboard: [
    [
      { text: '🕐 Full-Time', callback_data: 'T~'+j+'~F' },
      { text: '⏰ Part-Time', callback_data: 'T~'+j+'~P' }
    ],
    [
      { text: '📝 Contract',  callback_data: 'T~'+j+'~C' },
      { text: '🎓 Internship', callback_data: 'T~'+j+'~I' }
    ],
    [{ text: '🔄 Any Type', callback_data: 'T~'+j+'~A' }]
  ]
});

// After picking type, show location — each carries j+t forward
const locationKeyboard = (j, t) => ({
  inline_keyboard: [
    [
      { text: '🌍 Remote',         callback_data: 'L~'+j+'~'+t+'~0' },
      { text: '🇬🇧 United Kingdom', callback_data: 'L~'+j+'~'+t+'~1' }
    ],
    [
      { text: '🇺🇸 United States', callback_data: 'L~'+j+'~'+t+'~2' },
      { text: '🇳🇬 Nigeria',       callback_data: 'L~'+j+'~'+t+'~3' }
    ],
    [
      { text: '🇩🇪 Germany', callback_data: 'L~'+j+'~'+t+'~4' },
      { text: '🇨🇦 Canada',  callback_data: 'L~'+j+'~'+t+'~5' }
    ],
    [{ text: '✏️ Type a location', callback_data: 'L~'+j+'~'+t+'~X' }]
  ]
});

// After picking location, show experience — each carries j+t+l forward
const expKeyboard = (j, t, l) => ({
  inline_keyboard: [
    [{ text: '🌱 Entry Level (0-2 yrs)',  callback_data: 'E~'+j+'~'+t+'~'+l+'~0' }],
    [{ text: '🌿 Mid Level (2-5 yrs)',    callback_data: 'E~'+j+'~'+t+'~'+l+'~1' }],
    [{ text: '🌳 Senior Level (5+ yrs)',  callback_data: 'E~'+j+'~'+t+'~'+l+'~2' }],
    [{ text: '👔 Director / Executive',  callback_data: 'E~'+j+'~'+t+'~'+l+'~3' }],
    [{ text: '🎓 Internship Level',       callback_data: 'E~'+j+'~'+t+'~'+l+'~4' }],
    [{ text: '🔄 Any Level',             callback_data: 'E~'+j+'~'+t+'~'+l+'~5' }]
  ]
});

// After picking experience, show salary — each carries j+t+l+e forward
const salaryKeyboard = (j, t, l, e) => ({
  inline_keyboard: [
    [{ text: '💰 Under $30K / £25K',    callback_data: 'S~'+j+'~'+t+'~'+l+'~'+e+'~0' }],
    [{ text: '💰 $30K-60K / £25K-50K', callback_data: 'S~'+j+'~'+t+'~'+l+'~'+e+'~1' }],
    [{ text: '💰 $60K-100K / £50K-80K',callback_data: 'S~'+j+'~'+t+'~'+l+'~'+e+'~2' }],
    [{ text: '💰 $100K+ / £80K+',      callback_data: 'S~'+j+'~'+t+'~'+l+'~'+e+'~3' }],
    [{ text: '🚫 No Preference',        callback_data: 'S~'+j+'~'+t+'~'+l+'~'+e+'~4' }]
  ]
});

// After picking salary, show confirmation — carries everything forward
const confirmKeyboard = (j, t, l, e, s) => ({
  inline_keyboard: [
    [{ text: '🚀 Yes, Find My Jobs!', callback_data: 'CONFIRM~'+j+'~'+t+'~'+l+'~'+e+'~'+s }],
    [{ text: '✏️ Start Over',         callback_data: 'RESTART' }]
  ]
});

const deliveryKeyboard = () => ({
  inline_keyboard: [
    [{ text: '📊 Excel Spreadsheet (.xlsx)', callback_data: 'DEL~excel' }],
    [{ text: '📋 Text Summary in Chat',      callback_data: 'DEL~text'  }],
    [{ text: '🔥 Both! (Preview + Excel)',   callback_data: 'DEL~both'  }]
  ]
});

// ── Main response logic ──────────────────────────────────────
let responseText = '';
let keyboard     = null;
let startApify   = false;
let apifyPayload = null;
let sendFile     = false;
let deliveryType = null;

// ── Commands ─────────────────────────────────────────────────
if (messageText === '/start' || messageText === '/search') {
  delete staticData.awaitingCustom[chatId];
  responseText = 'Welcome to JobFindr, ' + username + '!\n\n🔍 What job are you looking for today?';
  keyboard = jobKeyboard();

} else if (messageText === '/status') {
  const job = staticData.scrapeJobs[chatId];
  responseText = job
    ? '⏳ Scrape in progress!\nSearching: ' + job.role + ' in ' + job.location + '\n\nI will message you the moment results are ready.'
    : '✅ No active scrape. Use /search to start one!';

} else if (messageText === '/help') {
  responseText = '🆘 JobFindr Help\n\n/start — New search\n/search — New search\n/status — Check active scrape\n/help — This message';

// ── Callback: user tapped a button ───────────────────────────
} else if (isCallback) {
  const parts = messageText.split('~');
  const step  = parts[0];

  // Decode state from callback_data
  const j = parts[1]; // job index
  const t = parts[2]; // type code
  const l = parts[3]; // location index
  const e = parts[4]; // experience index
  const s = parts[5]; // salary index

  switch (step) {

    case 'J': // User picked a job role
      if (j === 'X') {
        // User wants to type their own job — set a waiting flag
        staticData.awaitingCustom[chatId] = { type: 'JOB' };
        responseText = '✏️ Type the exact job title you are looking for:';
        // No keyboard — waiting for text
      } else {
        const jobName = resolveJob(j);
        responseText = '✅ ' + jobName + '\n\n⏰ What type of role?';
        keyboard = typeKeyboard(j);
      }
      break;

    case 'T': // User picked a job type
      responseText = '✅ ' + resolveType(t) + '\n\n📍 Where would you like to work?';
      keyboard = locationKeyboard(j, t);
      break;

    case 'L': // User picked a location
      if (l === 'X') {
        // User wants to type their own location
        staticData.awaitingCustom[chatId] = { type: 'LOC', j, t };
        responseText = '✏️ Type your preferred location (city, country, or Remote):';
        // No keyboard — waiting for text
      } else {
        responseText = '✅ ' + resolveLoc(l) + '\n\n🎯 What is your experience level?';
        keyboard = expKeyboard(j, t, l);
      }
      break;

    case 'E': // User picked experience level
      responseText = '✅ ' + resolveExp(e) + '\n\n💰 Any salary preference?';
      keyboard = salaryKeyboard(j, t, l, e);
      break;

    case 'S': // User picked salary — show summary
      const sumJob = resolveJob(j);
      const sumTyp = resolveType(t);
      const sumLoc = resolveLoc(l);
      const sumExp = resolveExp(e);
      const sumSal = resolveSal(s);
      responseText =
        '📋 Here is your search summary:\n\n' +
        '🔍 Role: ' + sumJob + '\n' +
        '⏰ Type: ' + sumTyp + '\n' +
        '📍 Location: ' + sumLoc + '\n' +
        '🎯 Experience: ' + sumExp + '\n' +
        '💰 Salary: ' + sumSal + '\n\n' +
        'Ready to search LinkedIn?';
      keyboard = confirmKeyboard(j, t, l, e, s);
      break;

    case 'CONFIRM': // User confirmed — fire Apify
      const cfJob = resolveJob(j);
      const cfTyp = resolveType(t);
      const cfLoc = resolveLoc(l);
      const cfExp = resolveExp(e);
      const cfSal = resolveSal(s);
      responseText =
        '⏳ Brilliant! Firing up the LinkedIn scraper now...\n\n' +
        '🔍 Searching: ' + cfJob + ' in ' + cfLoc + '\n' +
        '⏰ Type: ' + cfTyp + ' | 🎯 Level: ' + cfExp + '\n\n' +
        '☕ This takes about 5-10 minutes.\n' +
        'I will ping you the moment your results are ready!';
      startApify = true;
      apifyPayload = { jobRole: cfJob, jobType: cfTyp, location: cfLoc, experience: cfExp, salaryRange: cfSal, chatId };
      // Store active scrape reference
      staticData.scrapeJobs[chatId] = { role: cfJob, location: cfLoc };
      // Clean up custom text refs
      delete staticData.customJob[chatId];
      delete staticData.customLoc[chatId];
      break;

    case 'RESTART':
      delete staticData.awaitingCustom[chatId];
      responseText = '🔄 No worries! What job are you looking for?';
      keyboard = jobKeyboard();
      break;

    case 'DEL': // Delivery choice
      const format = parts[1]; // excel / text / both
      const res = staticData.results[chatId] || [];
      deliveryType = format;

      if (format === 'excel' || format === 'both') {
        sendFile = true;
      }

      if (format === 'text' || format === 'both') {
        const top10 = res.slice(0, 10).map((job, i) =>
          (i+1) + '. ' + (job.title || 'Unknown') +
          '\n   ' + (job.company || '?') + ' | ' + (job.location || '?') +
          '\n   ' + (job.jobUrl || job.applyUrl || 'No link')
        ).join('\n\n');
        responseText = '📋 Top ' + Math.min(10, res.length) + ' ' + (staticData.scrapeJobs[chatId]?.role || '') + ' Jobs:\n\n' + top10 + '\n\n_Showing ' + Math.min(10, res.length) + ' of ' + res.length + ' total_\n\nType /search to start a new search!';
      } else {
        responseText = '📊 Preparing your Excel file with ' + res.length + ' jobs... almost there!';
      }
      break;

    default:
      responseText = '👋 Welcome to JobFindr, ' + username + '! What job are you looking for today?';
      keyboard = jobKeyboard();
  }

// ── Plain text message — could be custom job or location ──────
} else if (!isCallback && messageText && !messageText.startsWith('/')) {
  const waiting = staticData.awaitingCustom[chatId];

  if (waiting && waiting.type === 'JOB') {
    // User typed a custom job title
    staticData.customJob[chatId] = messageText;
    delete staticData.awaitingCustom[chatId];
    // Use index 99 as placeholder for custom job in all subsequent buttons
    responseText = '✅ ' + messageText + ' — great choice!\n\n⏰ What type of role?';
    keyboard = typeKeyboard('99');

  } else if (waiting && waiting.type === 'LOC') {
    // User typed a custom location
    staticData.customLoc[chatId] = messageText;
    delete staticData.awaitingCustom[chatId];
    const { j, t } = waiting;
    // Use index 99 as placeholder for custom location in all subsequent buttons
    responseText = '✅ ' + messageText + ' noted.\n\n🎯 What is your experience level?';
    keyboard = expKeyboard(j, t, '99');

  } else {
    // Unknown plain text — show welcome
    responseText = '👋 Welcome to JobFindr, ' + username + '! What job are you looking for today?';
    keyboard = jobKeyboard();
  }

} else {
  // Fallback
  responseText = '👋 Welcome to JobFindr, ' + username + '! What job are you looking for today?';
  keyboard = jobKeyboard();
}

// Safety net — never send empty text
if (!responseText || responseText.trim() === '') {
  responseText = '👋 Welcome to JobFindr, ' + username + '! What job are you looking for today?';
  keyboard = jobKeyboard();
}

return [{ json: {
  chatId,
  callbackQueryId,
  text: responseText,
  keyboard,
  startApify,
  apifyPayload,
  sendFile,
  deliveryType,
  results: staticData.results[chatId] || []
} }];

